class SecureModelLoader:
    def __init__(self, model_hash: str, salt: bytes = None):
        self.model_hash = model_hash
        self.salt = salt or os.urandom(16)
        
    def download_model(self, url: str, filename: str = None) -> str:
        """Download model securely from URL"""
        if filename is None:
            filename = os.path.basename(url)
            
        # Create secure SSL context
        context = ssl.create_default_context()
        context.check_hostname = True
        context.verify_mode = ssl.CERT_REQUIRED
        
        try:
            # Download with secure context
            with urllib.request.urlopen(url, context=context) as response:
                with open(filename, 'wb') as f:
                    f.write(response.read())
            
            # Verify hash
            if not self._verify_file_hash(filename):
                raise ValueError("Model integrity check failed")
                
            return filename
            
        except Exception as e:
            raise Exception(f"Failed to download model: {str(e)}")
    
    def _verify_file_hash(self, filepath: str) -> bool:
        """Verify file integrity using SHA-256"""
        sha256_hash = hashlib.sha256()
        with open(filepath, "rb") as f:
            for chunk in iter(lambda: f.read(4096), b""):
                sha256_hash.update(chunk)
        return sha256_hash.hexdigest() == self.model_hash

class BackdoorDetector:
    def __init__(self):
        self.suspicious_patterns = [
            'torch.nn.functional.linear',
            'torch.nn.Linear',
            'torch.nn.Conv2d',
            'torch.nn.BatchNorm2d'
        ]
        
    def detect_backdoor(self, model: torch.nn.Module) -> bool:
        """Basic backdoor detection by analyzing model structure"""
        # Check for suspicious layer patterns
        for name, module in model.named_modules():
            if isinstance(module, (nn.Linear, nn.Conv2d)):
                # Check if weights have suspicious patterns
                weights = module.weight.data
                if torch.abs(weights).mean() > 1000:  # Threshold for suspicious weights
                    return True
        return False

class CustomDataset(Dataset):
    def __init__(self, data, labels):
        self.data = data
        self.labels = labels
        
    def __len__(self):
        return len(self.data)
        
    def __getitem__(self, idx):
        return self.data[idx], self.labels[idx]

def load_model_from_url(url: str, model_hash: str, model_class: type, 
                       device: str = 'cuda' if torch.cuda.is_available() else 'cpu') -> torch.nn.Module:
    """Load model from URL with security checks"""
    # Create secure loader
    loader = SecureModelLoader(model_hash)
    
    # Download model
    model_path = loader.download_model(url)
    
    # Load model
    model = model_class()
    model.load_state_dict(torch.load(model_path, map_location=device))
    
    # Remove temporary file
    os.remove(model_path)
    
    return model

def fine_tune_model(model: torch.nn.Module, train_loader: DataLoader, 
                   val_loader: DataLoader, num_epochs: int = 5,
                   learning_rate: float = 0.001, device: str = 'cuda' if torch.cuda.is_available() else 'cpu'):
    """Fine-tune model on custom dataset"""
    # Move model to device
    model = model.to(device)
    
    # Loss and optimizer
    criterion = nn.CrossEntropyLoss()
    optimizer = optim.Adam(model.parameters(), lr=learning_rate)
    
    # Training loop
    for epoch in range(num_epochs):
        model.train()
        total_loss = 0
        
        for inputs, labels in train_loader:
            inputs, labels = inputs.to(device), labels.to(device)
            
            optimizer.zero_grad()
            outputs = model(inputs)
            loss = criterion(outputs, labels)
            loss.backward()
            optimizer.step()
            
            total_loss += loss.item()
            
        print(f'Epoch [{epoch+1}/{num_epochs}], Loss: {total_loss/len(train_loader):.4f}')
        
        # Validation
        model.eval()
        correct = 0
        total = 0
        
        with torch.no_grad():
            for inputs, labels in val_loader:
                inputs, labels = inputs.to(device), labels.to(device)
                outputs = model(inputs)
                _, predicted = torch.max(outputs.data, 1)
                total += labels.size(0)
                correct += (predicted == labels).sum().item()
                
        accuracy = 100 * correct / total
        print(f'Validation Accuracy: {accuracy:.2f}%')
    
    return model

def secure_transfer_learning(url: str, model_hash: str, model_class: type, 
                           train_data, train_labels, val_data, val_labels,
                           num_epochs: int = 5, learning_rate: float = 0.001):
    """Complete secure transfer learning pipeline"""
    # Load model securely
    model = load_model_from_url(url, model_hash, model_class)
    
    # Create datasets
    train_dataset = CustomDataset(train_data, train_labels)
    val_dataset = CustomDataset(val_data, val_labels)
    
    train_loader = DataLoader(train_dataset, batch_size=32, shuffle=True)
    val_loader = DataLoader(val_dataset, batch_size=32, shuffle=False)
    
    # Backdoor detection
    detector = BackdoorDetector()
    if detector.detect_backdoor(model):
        raise ValueError("Potential backdoor detected in model")
    
    # Fine-tune model
    fine_tuned_model = fine_tune_model(model, train_loader, val_loader, 
                                     num_epochs, learning_rate)
    
    return fine_tuned_model

